+/// Helper: standard `OpenAI` embeddings success response.
+fn openai_embedding_response(
+    model: &str,
+    embeddings: &[Vec<f64>],
+    prompt_tokens: u32,
+) -> serde_json::Value {
+    json!({
+        "object": "list",
+        "data": embeddings.iter().enumerate().map(|(i, emb)| json!({
+            "object": "embedding",
+            "index": i,
+            "embedding": emb
+        })).collect::<Vec<_>>(),
+        "model": model,
+        "usage": {
+            "prompt_tokens": prompt_tokens,
+            "total_tokens": prompt_tokens
+        }
+    })
+}
